import bluetooth
from ble_advertising import advertising_payload
from machine import Pin, ADC
import struct
import time

# Constants for BLE
DEVICE_NAME = "ESP32_Device"
SERVICE_UUID = bluetooth.UUID("12345678-1234-5678-1234-56789abcdef0")
CHARACTERISTIC_UUID_SENSOR = bluetooth.UUID("12345678-1234-5678-1234-56789abcdef1")
CHARACTERISTIC_UUID_CONTROL = bluetooth.UUID("12345678-1234-5678-1234-56789abcdef2")

# Initialize BLE
ble = bluetooth.BLE()
ble.active(True)

# Sensor and Control Pins
sensor_pin = ADC(Pin(34))
control_pin = Pin(2, Pin.OUT)

# BLE GATT Server
def ble_irq(event, data):
    if event == bluetooth.IRQ_CENTRAL_CONNECT:
        print("Central connected")
    elif event == bluetooth.IRQ_CENTRAL_DISCONNECT:
        print("Central disconnected")
        start_advertising()

def read_sensor_data():
    # Read sensor data and convert to bytes
    value = sensor_pin.read()
    return struct.pack("<h", value)

def on_write_control(handle, data):
    # Handle control command
    if data == b'\x01':
        control_pin.on()
    elif data == b'\x00':
        control_pin.off()

def start_advertising():
    # Secure advertising with limited discoverability
    ble.gap_advertise(100, advertising_payload(name=DEVICE_NAME, services=[SERVICE_UUID], limited=True))

def setup_ble():
    ble.irq(ble_irq)
    
    # Define GATT server services and characteristics
    sensor_char = (CHARACTERISTIC_UUID_SENSOR, bluetooth.FLAG_READ | bluetooth.FLAG_NOTIFY)
    control_char = (CHARACTERISTIC_UUID_CONTROL, bluetooth.FLAG_WRITE)
    
    service = (SERVICE_UUID, (sensor_char, control_char))
    
    ble.gatts_register_services([service])
    
    # Assign handlers
    ble.gatts_set_buffer(sensor_char[0], 100)
    ble.gatts_set_buffer(control_char[0], 100)
    ble.gatts_write(control_char[0], b'\x00')
    ble.gatts_register_callback(control_char[0], on_write_control)

setup_ble()
start_advertising()

# Main loop
while True:
    # Notify sensor data periodically
    sensor_data = read_sensor_data()
    ble.gatts_notify(0, sensor_char[0], sensor_data)
    time.sleep(1)